+            .consolidate_page(page, &cfg)
+            .expect("consolidate no-op");
+        assert!(again.chain_len_before <= 1);
+        assert_eq!(again.cas_attempts, 0);
+        assert_eq!(
+            again.entries_count, 7,
+            "no-op consolidation must report the real entry count, not 0"
